package com.teamspace.teamspace.realtime.service;
import java.time.LocalDateTime; import java.util.Map; import java.util.UUID; import org.springframework.messaging.simp.SimpMessagingTemplate; import org.springframework.stereotype.Service; import com.teamspace.teamspace.realtime.dto.ProjectRealtimeEvent; import lombok.RequiredArgsConstructor;
@Service @RequiredArgsConstructor public class ProjectRealtimeService {private final SimpMessagingTemplate messaging;public void publish(Long projectId,Long taskId,String type,Long version,Map<String,Object> data){messaging.convertAndSend("/topic/projects/"+projectId+"/board",ProjectRealtimeEvent.builder().eventId(UUID.randomUUID()).projectId(projectId).taskId(taskId).eventType(type).version(version).data(data==null?Map.of():data).occurredAt(LocalDateTime.now()).build());}}
